#include <bits/stdc++.h>
using namespace std;
int n,t;
double ans;
struct nodel{
    double m;
    double v,c;
}p[100005];
bool cmp(nodel a,nodel b){
    return a.c>b.c;
}
int main(){
    cin>>n>>t;
    for(int i=1;i<=n;i++){
        cin>>p[i].m>>p[i].v;
        p[i].c=p[i].v/p[i].m;
    }
    sort(p+1,p+n+1,cmp);
    int i=1;
    while(t >= 0 && i<=n){
        if(t>=p[i].m){
            t-=p[i].m;
            ans+=p[i].v;
        }
        else{
            ans+=p[i].c*t;
            break;
        }
        i++;
    }
    printf("%.2lf",ans);
}
